"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[93391],{46233:(e,i,s)=>{s.r(i),s.d(i,{data:()=>a});const a={key:"v-d7a4cff6",path:"/windows/",title:"Windows",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[{level:2,title:"一、资源",slug:"一、资源",children:[{level:3,title:"1.1 官网windows下载",slug:"_1-1-官网windows下载",children:[]},{level:3,title:"1.2 一个全面的官网资源整合网站",slug:"_1-2-一个全面的官网资源整合网站",children:[]}]},{level:2,title:"二、快捷键",slug:"二、快捷键",children:[]},{level:2,title:"三、其他",slug:"三、其他",children:[{level:3,title:"3.1 运行命令列表",slug:"_3-1-运行命令列表",children:[]},{level:3,title:"3.2 管理Windows凭证",slug:"_3-2-管理windows凭证",children:[]},{level:3,title:"3.3 windows10安装net3.5",slug:"_3-3-windows10安装net3-5",children:[]},{level:3,title:"3.4 添加字体",slug:"_3-4-添加字体",children:[]},{level:3,title:"3.5服务器启用或关闭Windows功能",slug:"_3-5服务器启用或关闭windows功能",children:[]},{level:3,title:"3.6 WTG(移动系统)",slug:"_3-6-wtg-移动系统",children:[]},{level:3,title:"3.7 注册与删除服务",slug:"_3-7-注册与删除服务",children:[]}]},{level:2,title:"四、CMD",slug:"四、cmd",children:[{level:3,title:"4.1 命令",slug:"_4-1-命令",children:[]},{level:3,title:"4.2 bat",slug:"_4-2-bat",children:[]}]}],git:{updatedTime:1653451151e3,contributors:[{name:"panzhiyue",email:"30484534+panzhiyue@users.noreply.github.com",commits:1}]},filePathRelative:"windows/README.md"}},55122:(e,i,s)=>{s.r(i),s.d(i,{default:()=>d});const a=(0,s(57293).uE)('<p>[TOC]</p><h1 id="windows" tabindex="-1"><a class="header-anchor" href="#windows" aria-hidden="true">#</a> Windows</h1><h2 id="一、资源" tabindex="-1"><a class="header-anchor" href="#一、资源" aria-hidden="true">#</a> 一、资源</h2><h3 id="_1-1-官网windows下载" tabindex="-1"><a class="header-anchor" href="#_1-1-官网windows下载" aria-hidden="true">#</a> 1.1 官网windows下载</h3><h4 id="_1-1-1-windows10" tabindex="-1"><a class="header-anchor" href="#_1-1-1-windows10" aria-hidden="true">#</a> 1.1.1 windows10</h4><p>https://www.microsoft.com/zh-cn/software-download/windows10ISO</p><h4 id="_1-1-2-windows8" tabindex="-1"><a class="header-anchor" href="#_1-1-2-windows8" aria-hidden="true">#</a> 1.1.2 windows8</h4><p>https://www.microsoft.com/zh-cn/software-download/windows8ISO</p><h4 id="_1-1-3-windows7" tabindex="-1"><a class="header-anchor" href="#_1-1-3-windows7" aria-hidden="true">#</a> 1.1.3 Windows7</h4><p>https://www.microsoft.com/zh-cn/software-download/windows7</p><h4 id="_1-1-4-windowsxp" tabindex="-1"><a class="header-anchor" href="#_1-1-4-windowsxp" aria-hidden="true">#</a> 1.1.4 WindowsXP</h4><h3 id="_1-2-一个全面的官网资源整合网站" tabindex="-1"><a class="header-anchor" href="#_1-2-一个全面的官网资源整合网站" aria-hidden="true">#</a> 1.2 一个全面的官网资源整合网站</h3><p>https://msdn.itellyou.cn/</p><h2 id="二、快捷键" tabindex="-1"><a class="header-anchor" href="#二、快捷键" aria-hidden="true">#</a> 二、快捷键</h2><p>win+r:打开运行</p><h2 id="三、其他" tabindex="-1"><a class="header-anchor" href="#三、其他" aria-hidden="true">#</a> 三、其他</h2><h3 id="_3-1-运行命令列表" tabindex="-1"><a class="header-anchor" href="#_3-1-运行命令列表" aria-hidden="true">#</a> 3.1 运行命令列表</h3><p>cmd:打开终端</p><p>regedit:打开注册表</p><h3 id="_3-2-管理windows凭证" tabindex="-1"><a class="header-anchor" href="#_3-2-管理windows凭证" aria-hidden="true">#</a> 3.2 管理Windows凭证</h3><p>同事共享给我2个文件夹,分别用两套账号密码控制,我登录了第一个文件夹成功后开始登录第二个文件夹,会默认使用第一个文件夹的账号密码进行登录。</p><ol><li>打开控制面板-用户账户和家庭安全-用户账户-管理您的凭据</li></ol><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202111010846078.png" alt="image-20211101084534097"></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202111010846079.png" alt="image-20211101084551763"></p><ol start="2"><li>编辑</li></ol><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202111010846080.png" alt="image-20211101084603099"></p><h3 id="_3-3-windows10安装net3-5" tabindex="-1"><a class="header-anchor" href="#_3-3-windows10安装net3-5" aria-hidden="true">#</a> 3.3 windows10安装net3.5</h3><p>1.0x800f0950错误</p><p>mac m1芯片 使用parallels安装windows arm版本时无法安装.net3.5</p><p>解决方法:</p><p>(1)这么棘手的问题估计是一些系统文件出问题了，所以第一步就是修复系统：按“Windows+X”点击“命令提示符管理员”，输入“SFC /scannow”回车（该操作可能需要一段时间，please wait a minute...），再输入“dism /online /cleanup-image /restorehealth”回车。然后，估计还得等一会儿。</p><p>(2)解压iso镜像文件(必须时与安装的系统相同版本),进去，找到sxs文件夹，把它弄到D盘、E盘...随便哪个盘根目录下，记住，是根目录。我的是C盘。</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202111010846081.png" alt="image-20210418134634408"></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202111010846082.png" alt="image-20210418134540122"></p><p>5、然后按“Windows+X”点击“命令提示符管理员”，进入dos界面，键入（直接粘贴就行，复制粘贴的话，一定要把那个H换成你存储sxs文件夹的盘）dism.exe /online /enable-feature /featurename:NetFX3 /Source:C:\\sxs。然后会出来一个进度条，几分钟就可以了。</p><p>如果是以下提示很可能是windows版本不一致导致的</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202111010846083.png" alt="image-20210418134750833"></p><p>如果是以下提示则安装成功</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202111010846084.png" alt="image-20210418134816529"></p><h3 id="_3-4-添加字体" tabindex="-1"><a class="header-anchor" href="#_3-4-添加字体" aria-hidden="true">#</a> 3.4 添加字体</h3><p>1.下载所需字体</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202111010846085.png" alt="1603157885239"></p><ol start="2"><li>进入电脑的：C:\\Windows\\Fonts文件夹，这个文件夹专门用来存放系统字体的</li></ol><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202111010846086.png" alt="1603157936720"></p><ol start="3"><li>把刚才下载的字体集文件复制到这个文件夹下，系统会自动安装</li></ol><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202111010846087.png" alt="1603158005743"></p><ol start="4"><li>安装完成后就可以点击文件，选择预览，就可以看到了，在使用Word或其他工具时就可以选择这个字体啦</li></ol><h3 id="_3-5服务器启用或关闭windows功能" tabindex="-1"><a class="header-anchor" href="#_3-5服务器启用或关闭windows功能" aria-hidden="true">#</a> 3.5服务器启用或关闭Windows功能</h3><p>打开控制面板-&gt;查看方式&quot;类别&quot;-&gt;程序(启用或关闭windows功能)</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202111010846088.png" alt="1602740757894"></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202111010846089.png" alt="1602740792172"></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202111010846090.png" alt="1602740809211"></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202111010846092.png" alt="1602740851057"></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202111010846093.png" alt="1602740902069"></p><h3 id="_3-6-wtg-移动系统" tabindex="-1"><a class="header-anchor" href="#_3-6-wtg-移动系统" aria-hidden="true">#</a> 3.6 WTG(移动系统)</h3><p>http://www.360doc.com/content/19/0717/20/860_849425063.shtml</p><h3 id="_3-7-注册与删除服务" tabindex="-1"><a class="header-anchor" href="#_3-7-注册与删除服务" aria-hidden="true">#</a> 3.7 注册与删除服务</h3><p>1.注册服务</p><p>https://blog.csdn.net/woshiwangdaye/article/details/90482972</p><p>https://www.cnblogs.com/yepei/p/6218887.html</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>sc create ServiceName binPath= 路径 start= auto\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>2.删除服务</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>sc delete serverName\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>3.启动服务</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>sc start serverName\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>4.停止服务</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>sc stop serverName\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>管理员权限下的cmd 命令，格式：instsrv.exe 服务名 remove 例如：D:\\gateway\\Bat2Server\\instsrv.exe Sentinel remove</p><h2 id="四、cmd" tabindex="-1"><a class="header-anchor" href="#四、cmd" aria-hidden="true">#</a> 四、CMD</h2><h3 id="_4-1-命令" tabindex="-1"><a class="header-anchor" href="#_4-1-命令" aria-hidden="true">#</a> 4.1 命令</h3><h4 id="_4-1-1-ping-测试网络连接情况" tabindex="-1"><a class="header-anchor" href="#_4-1-1-ping-测试网络连接情况" aria-hidden="true">#</a> 4.1.1 ping: 测试网络连接情况</h4><ul><li><code>-n</code>：要发送的回显请求数</li><li><code>-t</code>：ping 主机直到中断</li><li><code>-i</code>：生存时间ttl</li><li><code>-6</code>：IPv6</li></ul><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>$ ping 192.168.20.8 -n 3\nPinging 192.168.20.8 with 32 bytes of data:\nReply from 192.168.20.8: bytes=32 time&lt;1ms TTL=64\nReply from 192.168.20.8: bytes=32 time&lt;1ms TTL=64\nReply from 192.168.20.8: bytes=32 time&lt;1ms TTL=64\n\nPing statistics for 192.168.20.8: \nPackets: Sent = 3, Received = 3, Lost = 0 (0% loss),\nApproximate round trip times in milli-seconds: \nMinimum = 0ms, Maximum = 0ms, Average = 0ms\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_4-1-2-netstat-协议统计和当前-tcp-ip-网络连接" tabindex="-1"><a class="header-anchor" href="#_4-1-2-netstat-协议统计和当前-tcp-ip-网络连接" aria-hidden="true">#</a> 4.1.2 netstat: 协议统计和当前 TCP/IP 网络连接</h4><ul><li><code>-t</code> 列出所有tcp连接</li><li><code>-a</code>：显示所有连接和侦听端口</li><li><code>-n</code>：以数字形式显示地址和端口号</li><li><code>-o</code>：显示进程 ID</li><li><code>-p proto</code>：显示指定的协议的连接，TCP、UDP、TCPv6 或 UDPv6</li><li><code>-s</code>：显示每个协议的统计。默认情况下，显示IP、IPv6、ICMP、ICMPv6、TCP、TCPv6、UDP 和 UDPv6的统计信息，可使用<code>-p</code> 选项指定协议。</li><li><code>-e</code>：显示以太网统计。此选项可以与 -s 选项结合使用。</li><li><code>-r</code>：显示路由信息</li></ul><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>Z:\\PZYDemo\\GZOL_Tool&gt;netstat -t\n\n活动连接\n\n  协议  本地地址          外部地址        状态           卸载状态\n\n  TCP    127.0.0.1:1116         DESKTOP-DSSD7C4:1120   ESTABLISHED     InHost\n  TCP    127.0.0.1:1117         DESKTOP-DSSD7C4:1119   ESTABLISHED     InHost\n  TCP    127.0.0.1:1119         DESKTOP-DSSD7C4:1117   ESTABLISHED     InHost\n  TCP    127.0.0.1:1120         DESKTOP-DSSD7C4:1116   ESTABLISHED     InHost\n  TCP    127.0.0.1:1333         DESKTOP-DSSD7C4:44244  ESTABLISHED     InHost\n  TCP    127.0.0.1:1815         DESKTOP-DSSD7C4:44244  ESTABLISHED     InHost\n  TCP    127.0.0.1:3300         DESKTOP-DSSD7C4:44244  ESTABLISHED     InHost\n  TCP    127.0.0.1:5042         DESKTOP-DSSD7C4:24801  ESTABLISHED     InHost\n  TCP    127.0.0.1:14807        DESKTOP-DSSD7C4:14817  ESTABLISHED     InHost\n  TCP    127.0.0.1:14808        DESKTOP-DSSD7C4:14820  ESTABLISHED     InHost\n  TCP    127.0.0.1:14817        DESKTOP-DSSD7C4:14807  ESTABLISHED     InHost\n  TCP    127.0.0.1:14820        DESKTOP-DSSD7C4:14808  ESTABLISHED     InHost\n  \n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_4-1-3-ipconfig-网卡信息" tabindex="-1"><a class="header-anchor" href="#_4-1-3-ipconfig-网卡信息" aria-hidden="true">#</a> 4.1.3 ipconfig:网卡信息</h4><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>$ ipconfig\n$ ipconfig /all\n$ netsh interface ipv4 show config\n$ netsh interface ipv6 show config\n$ wmic nic list brief\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_4-1-4路由配置" tabindex="-1"><a class="header-anchor" href="#_4-1-4路由配置" aria-hidden="true">#</a> 4.1.4路由配置</h4><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>route add [Destination] mask [netmask] [gw] metric [测量值]\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li>-p：添加永久路由</li><li>Destination： 指定该路由的网络目标。</li><li>mask：当添加一个网络路由时，需要使用网络掩码。</li><li>gw：路由数据包通过网关。注意，你指定的网关必须能够达到。</li><li>metric：设置路由跳数。</li></ul><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code># ipv4\n$ route -p add 23.23.23.0 mask 255.255.255.0 192.168.97.60\nroute delete 23.23.23.0# ipv6\n$ netsh interface ipv6 add/del route 2001::/64 &quot;Local Area Connection 2&quot; 2001::2\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="查看路由表" tabindex="-1"><a class="header-anchor" href="#查看路由表" aria-hidden="true">#</a> 查看路由表</h5><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>$ netstat -r\n$ route print\n$ route print -4\n$ route print -6\n$ netsh interface ipv4 show route\n$ netsh interface ipv6 show route\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="禁用启用网卡" tabindex="-1"><a class="header-anchor" href="#禁用启用网卡" aria-hidden="true">#</a> 禁用启用网卡</h5><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>$ netsh interface set interface eth0 disabled # 禁用网卡\n$ netsh interface set interface name=&quot;接口名称&quot; admin=DISABLE\n$ netsh interface set interface eth0 enabled #启用网卡\n$ netsh interface set interface name=&quot;接口名称&quot; admin=ENABLE\n$ netsh interface ipv6 set interface name=&quot;接口名称&quot; disable/enable\n$ netsh interface show interface #显示接口\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>通过python脚本自动化控制：</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>import osos.popen(&#39;netsh interface set interface name=&quot;接口名称&quot; admin=DISABLE&#39;)\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h5 id="释放、更新地址" tabindex="-1"><a class="header-anchor" href="#释放、更新地址" aria-hidden="true">#</a> 释放、更新地址</h5><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code># ipv4\n$ ipconfig /release\n$ ipconfig /renew\n# ipv6\n$ ipconfig /release6\n$ ipconfig /renew6\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="添加、删除ip地址" tabindex="-1"><a class="header-anchor" href="#添加、删除ip地址" aria-hidden="true">#</a> 添加、删除IP地址</h5><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code># ipv4\n$ netsh interface ip add address &quot;本地连接&quot; 192.168.1.100 255.255.255.0\n$ netsh interface ip delete address &quot;本地连接&quot; 192.168.1.100## 设置静态IP地址\n$ netsh interface ip set address name=&quot;eth1&quot; source=static address=192.168.5.125 mask=255.255.255.0\n# ipv6\n$ netsh interface ipv6 delete address 本地连接 2001::1\n$ netsh interface ipv6 add/del address 本地连接 2001::1\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_4-1-5-日期" tabindex="-1"><a class="header-anchor" href="#_4-1-5-日期" aria-hidden="true">#</a> 4.1.5 日期</h4><h5 id="_1-获取日期" tabindex="-1"><a class="header-anchor" href="#_1-获取日期" aria-hidden="true">#</a> 1.获取日期</h5><p><strong>语法</strong></p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>%date% \n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><strong>示例</strong></p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>echo %date%\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202111010847319.png" alt="1606361251524"></p><h5 id="_2-日期截取" tabindex="-1"><a class="header-anchor" href="#_2-日期截取" aria-hidden="true">#</a> 2.日期截取</h5><p><strong>语法</strong></p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>%date:~x,y%\n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>参数说明</strong></p><ul><li><p><strong>x</strong>是开始位置(从0开始)</p></li><li><p><strong>y</strong>是取得字符数</p></li></ul><p><strong>示例</strong></p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>echo 年:%date:~0,4%,月%date:~5,2%,日%date:~8,2%\n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202111010847321.png" alt="1606366029086"></p><h4 id="_4-1-6时间" tabindex="-1"><a class="header-anchor" href="#_4-1-6时间" aria-hidden="true">#</a> 4.1.6时间</h4><h5 id="_1-获取时间" tabindex="-1"><a class="header-anchor" href="#_1-获取时间" aria-hidden="true">#</a> 1.获取时间</h5><p><strong>语法</strong></p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>%time% \n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>示例</strong></p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>echo %time% \n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202111010847322.png" alt="1606361323044"></p><h5 id="_2-时间截取" tabindex="-1"><a class="header-anchor" href="#_2-时间截取" aria-hidden="true">#</a> 2.时间截取</h5><p><strong>语法</strong></p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>%time:~x,y%\n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>参数说明</strong></p><ul><li><p><strong>x</strong>是开始位置(从0开始)</p></li><li><p><strong>y</strong>是取得字符数</p></li></ul><p><strong>示例</strong></p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>echo 时%time:~0,2%,分%time:~3,2%,秒%time:~6,2%\n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202111010847323.png" alt="1606366189877"></p><h4 id="_4-1-7-文件夹" tabindex="-1"><a class="header-anchor" href="#_4-1-7-文件夹" aria-hidden="true">#</a> 4.1.7 文件夹</h4><h5 id="_1-创建文件夹" tabindex="-1"><a class="header-anchor" href="#_1-创建文件夹" aria-hidden="true">#</a> 1.创建文件夹</h5><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>md [盘符:\\][路径\\]新目录名\n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_4-1-8-用户" tabindex="-1"><a class="header-anchor" href="#_4-1-8-用户" aria-hidden="true">#</a> 4.1.8 用户</h4><h5 id="_1-创建用户" tabindex="-1"><a class="header-anchor" href="#_1-创建用户" aria-hidden="true">#</a> 1.创建用户</h5><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>net user 用户名 密码 /add\n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_4-1-9-echo打印信息" tabindex="-1"><a class="header-anchor" href="#_4-1-9-echo打印信息" aria-hidden="true">#</a> 4.1.9 echo打印信息</h4><p><strong>语法</strong></p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>echo\n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>示例</strong></p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>echo &quot;测试&quot;\n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202111010847324.png" alt="1606365644884"></p><h4 id="_4-1-10-路径" tabindex="-1"><a class="header-anchor" href="#_4-1-10-路径" aria-hidden="true">#</a> 4.1.10 路径</h4><h5 id="_1-获取当前盘符" tabindex="-1"><a class="header-anchor" href="#_1-获取当前盘符" aria-hidden="true">#</a> 1.获取当前盘符</h5><p><strong>语法</strong></p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>%~d0\n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>示例</strong></p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>echo 当前盘符:%~d0\npause\n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202111010847325.png" alt="1606132579470"></p><h5 id="_2-获取当前路径" tabindex="-1"><a class="header-anchor" href="#_2-获取当前路径" aria-hidden="true">#</a> 2.获取当前路径</h5><p><strong>语法</strong></p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>%cd%\n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>示例</strong></p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>echo 当前路径:%cd%\npause\n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202111010847326.png" alt="1606132737110"></p><h5 id="_3-当前执行命令行" tabindex="-1"><a class="header-anchor" href="#_3-当前执行命令行" aria-hidden="true">#</a> 3.当前执行命令行</h5><p><strong>语法</strong></p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>%0\n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>示例</strong></p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>echo 当前执行命令行:%0\npause\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202111010847327.png" alt="1606132952218"></p><h5 id="_4-当前bat文件路径" tabindex="-1"><a class="header-anchor" href="#_4-当前bat文件路径" aria-hidden="true">#</a> 4.当前bat文件路径</h5><p><strong>语法</strong></p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>%~dp0\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><strong>示例</strong></p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>echo 当前bat文件路径：%~dp0\npause\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202111010847328.png" alt="1606133094975"></p><h5 id="_5-当前bat文件短路径" tabindex="-1"><a class="header-anchor" href="#_5-当前bat文件短路径" aria-hidden="true">#</a> 5.当前bat文件短路径</h5><p><strong>语法</strong></p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>%~sdp0\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><strong>示例</strong></p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>echo 当前bat文件短路径：%~sdp0\npause\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202111010847329.png" alt="1606133213178"></p><h3 id="_4-2-bat" tabindex="-1"><a class="header-anchor" href="#_4-2-bat" aria-hidden="true">#</a> 4.2 bat</h3><h4 id="_1-执行结束不关闭窗口" tabindex="-1"><a class="header-anchor" href="#_1-执行结束不关闭窗口" aria-hidden="true">#</a> 1.执行结束不关闭窗口</h4><p><strong>语法</strong></p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>pause\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div>',169),n={},d=(0,s(63243).Z)(n,[["render",function(e,i){return a}]])},63243:(e,i)=>{i.Z=(e,i)=>{const s=e.__vccOpts||e;for(const[e,a]of i)s[e]=a;return s}}}]);